import{_ as e,o as t,c as o,ag as p}from"./chunks/framework.CYCRomDB.js";const a=JSON.parse('{"title":"Youtube 影片的 SEO，展開影片建立逐字稿","description":"影片該怎麼做好 SEO 呢? 除了設定好 Youtube 影片設定與基本資訊之外，還有個特別的方法增加影片的曝光度。 其實方法很簡單... 而且這個方式也不侷限在 Youtube, Vimeo 這類型的影音平台，主要目的在於影片的再利用! Youtube SEO 其實講 Youtube 影片的 SEO 有點言過其實。","frontmatter":{"title":"Youtube 影片的 SEO，展開影片建立逐字稿","date":"2026-03-02T00:00:00.000Z","updated":"2026-03-02T00:00:00.000Z","description":"影片該怎麼做好 SEO 呢? 除了設定好 Youtube 影片設定與基本資訊之外，還有個特別的方法增加影片的曝光度。 其實方法很簡單... 而且這個方式也不侷限在 Youtube, Vimeo 這類型的影音平台，主要目的在於影片的再利用! Youtube SEO 其實講 Youtube 影片的 SEO 有點言過其實。","author":"Cola","tags":[],"keywords":["php","seo"],"readingTime":"6 min read","readingMinutes":6,"permalink":"/youtube-video-transcript-for-seo","slug":"youtube-video-transcript-for-seo","issueId":6,"githubUrl":"https://github.com/cscolabear/cscolabear.github.io/issues/6"},"headers":[],"relativePath":"youtube-video-transcript-for-seo.md","filePath":"posts/youtube-video-transcript-for-seo.md","lastUpdated":1772944615000}');const s=e({name:"youtube-video-transcript-for-seo.md"},[["render",function(e,a,s,r,u,i){return t(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="youtube-影片的-seo-展開影片建立逐字稿" tabindex="-1">Youtube 影片的 SEO，展開影片建立逐字稿 <a class="header-anchor" href="#youtube-影片的-seo-展開影片建立逐字稿">#</a></h1><img width="393" height="249" alt="Image" src="https://github.com/user-attachments/assets/e39bec5b-e45d-4af6-a7aa-ce8bc9c3e881"><p>影片該怎麼做好 SEO 呢? 除了設定好 Youtube 影片設定與基本資訊之外，還有個特別的方法增加影片的曝光度。 其實方法很簡單... 而且這個方式也不侷限在 Youtube, Vimeo 這類型的影音平台，主要目的在於影片的再利用!</p><p></p><h2 id="youtube-seo" tabindex="-1">Youtube SEO <a class="header-anchor" href="#youtube-seo">#</a></h2><p>其實講 Youtube 影片的 SEO 有點言過其實。 單純的 Youtube SEO 主要重視在 影片的<strong>基本資訊</strong>設定</p><p><img src="https://github.com/user-attachments/assets/2e5f6dd4-48ca-429a-8428-906cc424e022" alt="Image"></p><p>在影片上設定正確的<strong>標題、內文和標籤</strong>就足以讓影片在 <strong>Youtube 上</strong>容易被找到了! 需要注意的幾個項目：</p><ul><li>標題</li><li>描述/內文 內文不要過長，最好分兩段重要的前文和說明的後文</li><li>Tag/標籤 設定約5~10個內的標籤</li><li>縮圖 在 Youtube 可以指定預覽圖，一張好的預覽圖可以決定使用者會不會點擊進入</li><li>雜項(地點,日期,類別...)</li><li>互動</li><li>資訊卡 互動類型的設定可以在影片撥放時出現想關連結，推薦連結、影片等 但是要注意不要過度濫用!</li></ul><p>上面就大概是一般 Youtube 的 SEO 重點了...</p><h2 id="影片的-seo-展開影片建立逐字稿" tabindex="-1">影片的 SEO，展開影片建立逐字稿 <a class="header-anchor" href="#影片的-seo-展開影片建立逐字稿">#</a></h2><p>內容產出非常辛苦、費工，每則文章、影片等內容我們都希望它能發揮最大效應，能被多次利用! 而影片不光是上傳到 Youtube，設定好相關 Tag 就好。</p><p>因此，利用文章展開這部影片，建立逐字稿。 讓不方便、沒時間看影片的使用者，也能透過文章快速瞭解影片內容與重點。</p><p>幾個重點展開你的影片：</p><ul><li>簡述：100字左右說明影片大綱</li><li>對白 ： 幾分幾秒 主講者說過的金句良言</li><li>截圖 ：將影片的特點、重點畫面截取出來 highlight 它</li><li>重要片段 : 拑入特定時間開始播放(<a href="https://support.google.com/youtube/answer/171780?hl=zh-Hant" target="_blank" rel="noreferrer">https://support.google.com/youtube/answer/171780?hl=zh-Hant</a>)</li></ul><p>以巴哈姆特的這篇新聞來講... <a href="http://gnn.gamer.com.tw/3/124883.html" target="_blank" rel="noreferrer">【TpGS 16】歷來規模最大台北電玩展明年1月登場 SEGA與Ubisoft參展 大宇與橘子回歸</a></p><ul><li>標題關連影片</li><li>文章前半部簡單敘述影片內容</li><li>插入影片主體</li><li>接著開始、依序展開影片內容，文章配合截圖</li></ul><p>可惜的是...如果他的大標題與分段再更清楚就好了...</p><p><img src="https://github.com/user-attachments/assets/c4fb091f-075e-4130-8647-b9d37d02763d" alt="Image"></p><p>(巴哈的這篇文章屬於新聞稿)</p><h2 id="影片展開示意" tabindex="-1">影片展開示意 <a class="header-anchor" href="#影片展開示意">#</a></h2><p>下為影片展開文章範例</p><p>[文章標題]</p><p></p><p>[文章簡述 - 約 100 字左右]</p><p></p><p>[拑入影片]</p><p></p><p>[內容索引] 利用<strong>錨點</strong>連結至文內小標</p><p></p><p>[小標 - 1]</p><p>05:30 主角說了什麼 [對話內容] 05:40 [對話內容] 05:50 [對話內容]</p><p>08:10 主角說了什麼 [對話內容] 08:20 [對話內容]</p><p>[截圖]</p><p>10:05 主角說了什麼 [對話內容] 10:10 [對話內容]</p><p>10:20 [精彩片段 - 對話內容]</p><p>[撥放 - 指定時間影片]</p><p></p><p>[小標 - 2]</p><p>10:40 [對話內容] 10:55 [對話內容]</p><p>11:05 [對話內容] 11:10 [對話內容]</p><p>11:20 [對話內容] 11:25 [對話內容]</p><p>11:35 [對話內容] 11:45 [對話內容]</p><p>[總結]</p><p></p><p>[相關連結] 可以放...產品連結、受訪者 FB 等連結</p><p>透過文章把影片內容記錄出來，讓讀著可以快速瞭解影片內容 能讓影片除了在 Youtube 平台也在別處留下可用資訊</p><p>把影片內的細節與重點，利用展開、逐字稿的方式，標示出重點或是圖片抓住使用者的目光。</p><h2 id="結論" tabindex="-1">結論 <a class="header-anchor" href="#結論">#</a></h2><p>影片逐字稿對 SEO 的目的是，不方便看影片的人，沒時間看影片的；文字閱讀比較能自行安排閱讀時間 拉出重點，如果是工具型影片，可以把逐字稿重點放在查閱型文字、工具型文字 (類似字典或食譜) 再者~ 就是讓辛苦拍攝、剪輯的影片產生再利用的資訊複利把內容 SEO 的效益極大化!!</p><hr><div class="github-discussion"><a href="https://github.com/cscolabear/cscolabear.github.io/issues/6" target="_blank" rel="noopener noreferrer"> 💬 在 GitHub 上討論這篇文章 </a></div>',52)])])}]]);export{a as __pageData,s as default};
